import json
import boto3
import requests
from typing import Dict, Any

def lambda_handler(event: Dict[str, Any], context):
    # Get the request headers from the event
    headers = event["Records"][0]["cf"]["request"]["headers"]
    
    # Check if X-Enrich-URL header is present in the request
    if "X-Enrich-URL" not in headers:
        return {
            "statusCode": 400,
            "body": "X-Enrich-URL header not found"
        }
    
    # Get the URL from the X-Enrich-URL header
    url = headers["X-Enrich-URL"][0]["value"]
    
    # Make an HTTP GET request to the specified URL
    response = requests.get(url)
    
    # If the response status code is not 200, return an error message
    if response.status_code != 200:
        return {
            "statusCode": response.status_code,
            "body": f"Error fetching data from URL {url}: {response.text}"
        }
    
    # Return the response body as JSON
    return {
        "statusCode": 200,
        "body": json.dumps(response.json())
    }